SELECT w.warehouse_name
FROM warehouses w
WHERE w.current_utilization = (SELECT MIN(current_utilization) FROM warehouses);

SELECT part_num
FROM parts
WHERE unit_cost > (SELECT AVG(unit_cost) FROM parts);

SELECT inventory_id, warehouse_id, location, capacity, current_utilization, status
FROM inventories
WHERE current_utilization > 80;

SELECT inventories.location, warehouses.warehouse_name
FROM inventories
INNER JOIN warehouses ON inventories.warehouse_id = warehouses.warehouse_id;

SELECT COUNT(*) 
FROM part_suppliers 
WHERE status = 'active';

SELECT part_num
FROM parts
WHERE status <> 'active' AND lead_time > 7;
